//about.bgov.com/" target="_blank"> Bloomberg Government</a> product, where I spent over three years crafting data visualizations and scalable UI features. A couple notable features I built include an interactive Sankey chart for the <a class="about-me-link" href="https://about.bgov.com/products/federal-budget-and-spending/" target="_blank">Federal Budget and Spending Insight </a> product and a bill density heat map for the <a class="about-me-link" href="https://about.bgov.com/products/public-affairs-intelligence/federal-and-state-tracking/" target="_blank">Federal and State Tracking</a> product. <br><br> I specialize in Vue.js, D3.js, TypeScript, and Javascript, with a passion for turning complex data into interfaces that fell effortless to use. Outside of frontend work, I&#39;ve been expanding into cloud architecture and infrastructure, earning three AWS certifications along the way. </p></div><div class="about-img fade-in"><a href="https://www.linkedin.com/in/brenda-q-50778617a/" target="_blank"><img class="profile-img" src="'+ug+'" width="250px"></a></div></div>',2)])])}const gg=jn(dg,[["render",pg]]),mg="/assets/aws-certified-developer-associate-vWREBYx-.png",_g="/assets/aws-certified-ai-practitioner-BgDGWpC_.png",bg="/assets/aws-certified-cloud-practitioner-BuHr8jxj.png",vg={},yg={id:"CertificationsSection"};function wg(e,t){return Te(),ke("div",yg,[...t[0]||(t[0]=[Gr('<div class="section-title"> Certifications <div class="period-style">.</div></div><div class="certifications-wrapper"><a class="cert-card" href="https://www.credly.com/badges/dea3424f-39e0-4280-90c5-32ea8c5a4fe9/public_url" target="_blank"><img class="cert-img" src="'+mg+'"></a><a class="cert-card" href="https://www.credly.com/badges/970a77eb-aac5-44d7-84b2-48893644277f/public_url" target="_blank"><img class="cert-img" src="'+_g+'"></a><a class="cert-card" href="https://www.credly.com/badges/e3f5420d-5f22-4d5f-840b-a5168f3e9495/public_url" target="_blank"><img class="cert-img" src="'+bg+'"></a><